// Backend API configuration and client
const API_BASE_URL = typeof window !== 'undefined' ? '' : (process.env.NEXT_PUBLIC_API_URL || '');

export const api = {
  baseUrl: API_BASE_URL,

  // Health check
  async health() {
    const res = await fetch(`${API_BASE_URL}/health`);
    return res.json();
  },

  // File operations
  files: {
    // List all files or filter by type
    async list(fileType?: string, skip = 0, limit = 100) {
      let url = `${API_BASE_URL}/api/files?skip=${skip}&limit=${limit}`;
      if (fileType) {
        url += `&file_type=${fileType}`;
      }
      const res = await fetch(url);
      if (!res.ok) throw new Error(`Failed to list files: ${res.statusText}`);
      return res.json();
    },

    // Get file info
    async getInfo(fileId: string) {
      const res = await fetch(`${API_BASE_URL}/api/files/${fileId}`);
      if (!res.ok) throw new Error(`Failed to get file info: ${res.statusText}`);
      return res.json();
    },

    // Upload file
    async upload(file: File, description?: string, tags?: string) {
      const formData = new FormData();
      formData.append('file', file);
      if (description) formData.append('description', description);
      if (tags) formData.append('tags', tags);
      
      const res = await fetch(`${API_BASE_URL}/api/upload`, {
        method: 'POST',
        body: formData,
      });

      if (!res.ok) {
        const error = await res.json();
        throw new Error(error.detail || 'Upload failed');
      }
      
      return res.json();
    },

    // Stable URL for previews, video playback, and direct browser fetches.
    downloadUrl(fileId: string) {
      return `${API_BASE_URL}/api/download/${encodeURIComponent(fileId)}`;
    },

    // Download file
    async download(fileId: string) {
      const url = api.files.downloadUrl(fileId);
      console.log('Downloading from:', url);
      
      try {
        const res = await fetch(url);
        console.log('Download response status:', res.status, res.statusText);
        
        if (!res.ok) {
          const errorText = await res.text();
          console.error('Download error response:', errorText);
          throw new Error(`HTTP ${res.status}: ${res.statusText}`);
        }
        
        const contentType = res.headers.get('content-type');
        console.log('Content-Type:', contentType);
        
        const blob = await res.blob();
        console.log('Blob size:', blob.size, 'bytes');
        
        if (blob.size === 0) {
          throw new Error('Downloaded file is empty');
        }
        
        return blob;
      } catch (error) {
        console.error('Download failed:', error);
        throw error;
      }
    },

    // Delete file
    async delete(fileId: string) {
      const res = await fetch(`${API_BASE_URL}/api/files/${fileId}`, {
        method: 'DELETE',
      });
      if (!res.ok) throw new Error('Delete failed');
      return res.json();
    },

    // Get file statistics
    async getStats() {
      const res = await fetch(`${API_BASE_URL}/api/files/stats/summary`);
      if (!res.ok) throw new Error('Failed to get stats');
      return res.json();
    },
  },

  // Folder operations
  folders: {
    // Create folder
    async create(name: string, parentId?: string) {
      const res = await fetch(`${API_BASE_URL}/api/folders`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ name, parent_id: parentId }),
      });
      if (!res.ok) throw new Error('Failed to create folder');
      return res.json();
    },

    // List folders
    async list(parentId?: string) {
      let url = `${API_BASE_URL}/api/folders`;
      if (parentId) {
        url += `?parent_id=${parentId}`;
      }
      const res = await fetch(url);
      if (!res.ok) throw new Error('Failed to list folders');
      return res.json();
    },

    // Get folder contents
    async getContents(folderId: string) {
      const res = await fetch(`${API_BASE_URL}/api/folders/${folderId}`);
      if (!res.ok) throw new Error('Failed to get folder contents');
      return res.json();
    },

    // Delete folder
    async delete(folderId: string) {
      const res = await fetch(`${API_BASE_URL}/api/folders/${folderId}`, {
        method: 'DELETE',
      });
      if (!res.ok) throw new Error('Failed to delete folder');
      return res.json();
    },
  },
};
